        // Find the first element strictly greater than X.
        auto it = upper_bound(nums_ptr->begin(), nums_ptr->end(), X);

        // The index of the last element <= X is (it - nums_ptr->begin()) - 1.
        int r_limit = (it - nums_ptr->begin()) - 1;

