                C_X = count_up_to_R_prime - count_before_l;
            }

            // Check if the M-th even number (2M) is the k-th remaining number.
            // Remaining count <= 2M is M - C(X). We need this count to be >= k.
            if (M - C_X >= k) {
                M_ans = M;
                high_M = M - 1; // Try to find a smaller M
            } else {
                low_M = M + 1; // Need a larger M
            }
        }

        results.push_back(2LL * M_ans);
    }

    return results;
}

