#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

/**
 * @brief Solves the problem by using binary search on the resulting rank M=X/2, 
 * where X is the target even number.
 * 
 * The time complexity is O(N + Q * log(M_max) * log N).
 */
std::vector<long long> solve(std::vector<long long> nums, std::vector<std::vector<long long>> queries) {
    int N = nums.size();

    // Step 1: Precompute prefix sums of even numbers in nums.
    // P[i] stores the count of even numbers in nums[0...i].
    std::vector<int> P(N);
    int count = 0;
    for (int i = 0; i < N; ++i) {
        if (nums[i] % 2 == 0) {
            count++;
        }
        P[i] = count;
    }

    std::vector<long long> results;

    // Step 2: Process each query
    for (const auto& query : queries) {
        // query = [l, r, k]
        long long l = query[0];
        long long r = query[1];
        long long k = query[2];

        // Binary search for M such that the M-th positive even number (2M) 
        // is the k-th remaining even number.

        // M must be at least 1.
        // M_max is roughly k + N, since at most N evens are removed.
        // Since k <= 10^9 and N <= 10^5, 2*10^9 + 10^5 is safe for the upper bound of M.
        long long low_M = 1;
        // Using 2e9 + 2 as a very safe upper bound for M
        long long high_M = 2000000000LL + N + 2; 
        long long M_ans = high_M + 1;

        while (low_M <= high_M) {
            long long M = low_M + (high_M - low_M) / 2;
            long long X = 2LL * M;

            // Calculate C(X): count of even numbers in nums[l..r] that are <= X.

            // 1. Find j_max: index of the rightmost element in nums <= X.
            auto it_upper = std::upper_bound(nums.begin(), nums.end(), X);
            int j_upper = std::distance(nums.begin(), it_upper);
            int j_max = j_upper - 1;

            // 2. Determine the effective range end R' = min(r, j_max).
            // Since r is guaranteed to be valid index in nums, and j_max is >= -1, 
            // we take min of r and j_max, constrained by l.
            long long R_prime_ll = std::min(r, (long long)j_max);

            int C_X = 0;
            if (l <= R_prime_ll) {
                int R_prime = (int)R_prime_ll;

                // Count evens in nums[l..R_prime] using prefix sums P.
                int count_up_to_R_prime = P[R_prime];
                int count_before_l = (l == 0) ? 0 : P[(int)(l - 1)];
                C_X = count_up_to_R_prime - count_before_l;
            }

            // Check if the M-th even number (2M) is the k-th remaining number.
            // Remaining count <= 2M is M - C(X). We need this count to be >= k.
            if (M - C_X >= k) {
                M_ans = M;
                high_M = M - 1; // Try to find a smaller M
            } else {
                low_M = M + 1; // Need a larger M
            }
        }

        results.push_back(2LL * M_ans);
    }

    return results;
}
